SABsumDict = dict([((n,x,y),sum([nSAB(n-_,y) for _ in range(x)])) for n in range(X) for x in range(X) for y in range(Y)])    
    
def SABencode(sizes):    
    k = len(sizes)
    n = sum(sizes)
    f = sizes[0]
    if k == 1:
        return 0
    prevCombs = SABsumDict.get((n,f,k-1),0) #0 if f == 0 else SABsumDict[(n,f,k-1)]
    return prevCombs+SABencode(sizes[1:])

def SABdecode(conf,n,k):
    if k == 1:
        return [n]
    f = 0
    while SABsumDict[(n,f+1,k-1)] <= conf:
        f += 1
    return [f] + SABdecode(conf-SABsumDict[(n,f,k-1)],n-f,k-1)

def calcErr(quantization_levels):
    def integrand(x):
        imin, qmin = max([(i,q) for i,q in enumerate(quantization_levels)  if q < x])
        qmax = quantization_levels[imin+1]
        p = (x-qmin)/(qmax-qmin)
        return (p * (qmax-x)**2 + (1-p) * (x-qmin)**2) * exp(-x**2/2)  / sqrt(2*pi)   
        
    return(quad(integrand, -T, T, args=())[0])


