eps = 1e-7   

def calcError(quantization_levels):
    def calcError_in_a_b(a,b):
        def integrand(t):
            return ((b-t)/(b-a) * (t-a)**2 + (t-a)/(b-a) * (t-b)**2) * exp(-t**2/2) 
        return quad(integrand, a, b, args=())[0]
    def calcError_in_minus_a_a(a):
        def integrand(t):
            return ((a+t)/(2*a) * (t-a)**2 + (a-t)/(2*a) * (t+a)**2) * exp(-t**2/2) 
        return quad(integrand, 0, a, args=())[0]        
    return calcError_in_minus_a_a(quantization_levels[0]) + sum([calcError_in_a_b(quantization_levels[i],quantization_levels[i+1]) for i in range(len(quantization_levels)-1)])
    


def opt_quantization_levels(k,T, initialization = None):
    def opt_x_given_T(T):
        def integrand_0_x(t, x, T):
            return (x**2 - t**2)*exp(-t**2/2)
            
        def integrand_x_T(t, x, T):
            return (T-t)*(t-x)*exp(-t**2/2) 
        left = 0.0
        right = T
        I = 1
        I_x_plus_eps = 0
        while (right - left) > 1e-14:
            x = (left + right) / 2
            I = quad(integrand_0_x, 0, x, args=(x,T))[0] + quad(integrand_x_T, x, T, args=(x,T))[0]
            I_x_plus_eps = quad(integrand_0_x, 0, x+eps, args=(x+eps,T))[0] + quad(integrand_x_T, x+eps, T, args=(x+eps,T))[0]
            #print(x, I, I-I_x_plus_eps)
            #print(x)
            if (I < I_x_plus_eps):
                right = x
            else:
                left = x
        return x
                
    def opt_x_given_a_b(a,b):
        def integrand_a_x(t, x, a, b):
            return (a-t)*(t-x)*exp(-t**2/2)
            
        def integrand_x_b(t, x, a, b):
            return (b-t)*(t-x)*exp(-t**2/2)     

        left = a
        right = b
        I = 1
        I_x_plus_eps = 0
        while (right - left) > 1e-14:
            x = (left + right) / 2
            I = quad(integrand_a_x, a, x, args=(x,a,b))[0] + quad(integrand_x_b, x, b, args=(x,a,b))[0]
            I_x_plus_eps = quad(integrand_a_x, a, x+eps, args=(x+eps,a,b))[0] + quad(integrand_x_b, x+eps, b, args=(x+eps,a,b))[0]
            #print(x, I, I-I_x_plus_eps)
            #print(x)
            if (I < I_x_plus_eps):
                right = x
            else:
                left = x        
            
        return x

    if (k == 1):
        return [opt_x_given_T(T), T]
        
    #print(opt_x_given_T(2.0))
    prevError = 2000
    cur_err = 1000
    if initialization is not None:
        quantization_levels = initialization
    else:
        quantization_levels = [i*T / float(k+1) for i in range(1,k+1)] + [T]
    #for iter in range(10):
    while (prevError - cur_err > 1e-14):
        prevError = cur_err
        cur_err = calcError(quantization_levels)
        #print(quantization_levels, cur_err, cur_err-prevError)
        #print(opt_x_given_T(quantization_levels[1]),quantization_levels[1])
        new_quantization_levels = [opt_x_given_T(quantization_levels[1])] \
            + [opt_x_given_a_b(quantization_levels[i-1],quantization_levels[i+1]) for i in range(1,k)]
        
        quantization_levels = new_quantization_levels + [T]
    return quantization_levels   

